import React from 'react';
import { useTheme } from '../context/ThemeContext';
import translations from '../translations';
import { FiAward, FiCalendar } from 'react-icons/fi';

const Education = () => {
  const { language } = useTheme();
  const t = translations[language].education;

  return (
    <section id="education" className="education">
      <div className="container">
        <div className="section-header">
          <h2 className="section-title">{t.title}</h2>
          <p className="section-subtitle">{t.subtitle}</p>
        </div>

        <div className="education-content">
          {/* Formations */}
          <div className="education-column">
            <h3 className="education-column-title">
              <span className="education-icon">🎓</span>
              {t.formationsTitle}
            </h3>
            <div className="education-list">
              {t.formations.map((item, index) => (
                <div key={index} className="education-card">
                  <div className="education-card-header">
                    <h4 className="education-card-title">{item.title}</h4>
                    <span className="education-card-date">
                      <FiCalendar />
                      {item.year}
                    </span>
                  </div>
                  <p className="education-card-institution">{item.institution}</p>
                  {item.description && (
                    <p className="education-card-description">{item.description}</p>
                  )}
                </div>
              ))}
            </div>
          </div>

          {/* Certifications */}
          <div className="education-column">
            <h3 className="education-column-title">
              <span className="education-icon">🏆</span>
              {t.certificationsTitle}
            </h3>
            <div className="certifications-grid">
              {t.certifications.map((cert, index) => (
                <div key={index} className="certification-card">
                  <div className="certification-badge">
                    <FiAward />
                  </div>
                  <div className="certification-info">
                    <h4 className="certification-title">{cert.title}</h4>
                    <p className="certification-issuer">{cert.issuer}</p>
                    <span className="certification-year">{cert.year}</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Education;
